import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Properly handling buffer size and input validation
        int maxLength = 10;
        byte[] buffer = new byte[maxLength];

        if (name.length() > maxLength) {
            System.arraycopy(name.getBytes(StandardCharsets.UTF_8), 0, buffer, 0, maxLength);
        } else {
            System.arraycopy(name.getBytes(StandardCharsets.UTF_8), 0, buffer, 0, name.length());
        }

        System.out.println("Welcome, " + new String(buffer, StandardCharsets.UTF_8).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
